        [DataRow(".gif", DisplayName = "gif")]
        [DataRow(".bmp", DisplayName = "bmp")]
        public void Create_Post_ValidFileExtensions_AreAccepted(string extension)
        {
            // Verify that valid extensions pass the extension check
            // (they'll proceed to the file I/O which may fail, but the extension check passes)
            using var context = CreateCourseContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course { CourseID = 2001, Title = "Physics", Credits = 4, DepartmentID = 1 };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns($"image{extension}");
            mockFile.Setup(f => f.Length).Returns(1024);
            // CopyTo will be called if we get past validation — set up to do nothing harmful
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = controller.Create(course, mockFile.Object);

            // Should NOT have the extension error
            Assert.IsFalse(controller.ModelState.ContainsKey("teachingMaterialImage") &&
                controller.ModelState["teachingMaterialImage"].Errors.Any(e => e.ErrorMessage.Contains("valid image file")));
        }

