using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndexAndContainsItems()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(new[] { 1, 2, 3 }, list);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 → 4 pages")]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 → 2 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 → 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 → 0 pages")]
        [DataRow(7, 7, 1, DisplayName = "Exact fit → 1 page")]
        [DataRow(15, 4, 4, DisplayName = "15 items, page size 4 → 4 pages")]
        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // 10 items, pageSize 5 → 2 pages, on page 2
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_BeforeLastPage_ReturnsTrue()
        {
            // 10 items, pageSize 5 → 2 pages, on page 1
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);  // Page 2 starts at item 6
            Assert.AreEqual(10, result[4]); // Ends at item 10
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.IsTrue(result.HasNextPage);
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.AreEqual(2, result.Count); // Only 2 items on page 3 of 12
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
            Assert.IsFalse(result.HasNextPage);
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<string>().AsQueryable();

            var result = PaginatedList<string>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain the static queue to avoid interference from other tests
            TestHelper.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            // Drain again so we don't leak into other tests
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_SetsAllFields()
        {
            _sut.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Smith"));
            Assert.IsTrue(notification.Message.Contains("created"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
            Assert.IsTrue(notification.Message.Contains("updated"));
        }

        [TestMethod]
        public void SendNotification_NullDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "5", null, EntityOperation.DELETE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 5"));
            Assert.IsTrue(notification.Message.Contains("deleted"));
        }

        [TestMethod]
        public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "5", "   ", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 5"));
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Course", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE → created")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE → updated")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE → deleted")]
        public void SendNotification_OperationTypes_GenerateCorrectVerb(EntityOperation operation, string expectedVerb)
        {
            _sut.SendNotification("Entity", "1", "TestEntity", operation, "User");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Expected message to contain '{expectedVerb}', but was '{notification.Message}'");
        }

        [TestMethod]
        public void SendNotification_CreateWithDisplayName_MessageFormat()
        {
            _sut.SendNotification("Department", "10", "Engineering", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("New Department 'Engineering' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateWithDisplayName_MessageFormat()
        {
            _sut.SendNotification("Department", "10", "Engineering", EntityOperation.UPDATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteWithDisplayName_MessageFormat()
        {
            _sut.SendNotification("Department", "10", "Engineering", EntityOperation.DELETE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_CreateWithoutDisplayName_MessageFormat()
        {
            _sut.SendNotification("Course", "42", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueIsEmpty_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendAndReceive_FIFO_Order()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();
            var fourth = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
            Assert.AreEqual("C", third.EntityType);
            Assert.IsNull(fourth); // Queue is now empty
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var before = DateTime.Now.AddSeconds(-1);

            _sut.SendNotification("Entity", "1", EntityOperation.CREATE);

            var after = DateTime.Now.AddSeconds(1);
            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            _sut.SendNotification("Entity", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the current in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
            _sut.MarkAsRead(-1);
            // Should not throw any exceptions
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should not throw
        }

        [TestMethod]
        public void SendNotification_TwoParamOverload_CallsFiveParamOverload()
        {
            // Tests the 4-param overload that delegates to the 5-param overload
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("TestUser", notification.CreatedBy);
            // No display name → should use ID-based message
            Assert.IsTrue(notification.Message.Contains("ID: 1"));
        }
    }
}

