using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void GetNotifications_WhenQueueEmpty_ReturnsJsonWithEmptyList()
        {
            using var context = TestHelper.CreateContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
            // Verify the anonymous type has a success property
            var successProp = result.Value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp, "Result should have a 'success' property");
            Assert.IsTrue((bool)successProp.GetValue(result.Value));

            var countProp = result.Value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp, "Result should have a 'count' property");
            Assert.AreEqual(0, (int)countProp.GetValue(result.Value));
        }

        [TestMethod]
        public void GetNotifications_WhenQueueHasItems_ReturnsNotifications()
        {
            // Pre-populate the static queue
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
            svc.SendNotification("Course", "2", "Math", EntityOperation.UPDATE, "Admin");

            using var context = TestHelper.CreateContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            var successProp = result.Value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(result.Value));

            var countProp = result.Value.GetType().GetProperty("count");
            Assert.AreEqual(2, (int)countProp.GetValue(result.Value));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            // Add 15 notifications
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            using var context = TestHelper.CreateContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            var countProp = result.Value.GetType().GetProperty("count");
            Assert.AreEqual(10, (int)countProp.GetValue(result.Value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            using var context = TestHelper.CreateContext();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.IsNotNull(result);
