+    [TestClass]
+    public sealed class NotificationServiceTests
+    {
+        private NotificationService _sut;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            // Drain the static queue to avoid interference from other tests
+            TestHelper.DrainNotificationQueue();
+            _sut = new NotificationService();
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            _sut?.Dispose();
+            // Drain again so we don't leak into other tests
+            TestHelper.DrainNotificationQueue();
+        }
+
+        [TestMethod]
+        public void SendNotification_WithDisplayName_SetsAllFields()
+        {
+            _sut.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Student", notification.EntityType);
+            Assert.AreEqual("1", notification.EntityId);
+            Assert.AreEqual("CREATE", notification.Operation);
+            Assert.AreEqual("Admin", notification.CreatedBy);
+            Assert.IsFalse(notification.IsRead);
+            Assert.IsTrue(notification.Message.Contains("John Smith"));
+            Assert.IsTrue(notification.Message.Contains("created"));
+        }
+
+        [TestMethod]
+        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
+        {
+            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "System");
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.IsTrue(notification.Message.Contains("ID: 42"));
+            Assert.IsTrue(notification.Message.Contains("updated"));
+        }
+
+        [TestMethod]
+        public void SendNotification_NullDisplayName_UsesIdInMessage()
+        {
+            _sut.SendNotification("Student", "5", null, EntityOperation.DELETE, "Admin");
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.IsTrue(notification.Message.Contains("ID: 5"));
+            Assert.IsTrue(notification.Message.Contains("deleted"));
+        }
+
+        [TestMethod]
+        public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
+        {
+            _sut.SendNotification("Student", "5", "   ", EntityOperation.CREATE, "Admin");
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.IsTrue(notification.Message.Contains("ID: 5"));
+        }
+
+        [TestMethod]
+        public void SendNotification_NullUserName_DefaultsToSystem()
+        {
+            _sut.SendNotification("Course", "1", EntityOperation.CREATE);
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE → created")]
+        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE → updated")]
+        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE → deleted")]
+        public void SendNotification_OperationTypes_GenerateCorrectVerb(EntityOperation operation, string expectedVerb)
+        {
+            _sut.SendNotification("Entity", "1", "TestEntity", operation, "User");
+
+            var notification = _sut.ReceiveNotification();
+
+            Assert.IsNotNull(notification);
+            Assert.IsTrue(notification.Message.Contains(expectedVerb),
+                $"Expected message to contain '{expectedVerb}', but was '{notification.Message}'");
